import React from 'react';
import { useNotifications } from '../components/NotificationSystem';
import useChatStore from '../services/chatState';

export default function ChatList() {
  const activeChats = useChatStore(state => state.activeChats);
  const setCurrentChat = useChatStore(state => state.setCurrentChat);

  return (
    <div className="p-4">
      <h2 className="text-lg font-bold mb-4">Conversații Active</h2>
      <div className="space-y-2">
        {activeChats.length === 0 ? (
          <p className="text-gray-500 text-sm">Nu ai conversații active</p>
        ) : (
          activeChats.map(chat => (
            <div 
              key={chat.id}
              onClick={() => setCurrentChat(chat.id)}
              className="p-3 bg-white rounded-lg shadow cursor-pointer hover:bg-gray-50"
            >
              <p className="font-medium">{chat.name}</p>
              {chat.lastMessage && (
                <p className="text-sm text-gray-500 truncate">
                  {chat.lastMessage}
                </p>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
